    public function get_message_hash(string $unifiedChannel, ?string $symbol = null, ?string $extra = null) {
        $hash = $unifiedChannel;
        if ($symbol !== null) {
            $hash .= '::' . $symbol;
        } else {
            $hash .= 's'; // tickers, orderbooks, ohlcvs ...
        }
        if ($extra !== null) {
            $hash .= '::' . $extra;
        }
        return $hash;
    }

    public function subscribe_public($messageHash, $params = array ()) {
        return Async\async(function () use ($messageHash, $params) {
            $url = $this->urls['api']['ws'];
            $request = array(
                'type' => 'subscribe',
            );
            $subscription = array(
                'messageHash' => $messageHash,
                'params' => $params,
            );
            return Async\await($this->watch($url, $messageHash, $this->extend($request, $params), $messageHash, $subscription));
        }) ();
    }

